import React from "react";

export default function ProfileScreen({ user = { name: "", email: "", joinedDate: "" }, onLogout, darkMode }) {
  return (
    <div className={`px-6 pb-24 min-h-screen ${darkMode ? "bg-gray-900 text-white" : "bg-gray-50 text-gray-900"}`}>

      {/* Header */}
      <h1 className="text-2xl font-bold mb-6">Profile</h1>

      {/* Profile Card */}
      <div className={`bg-white ${darkMode ? "bg-gray-800" : ""} p-6 rounded-2xl border ${darkMode ? "border-gray-700" : "border-gray-100"} shadow-sm space-y-4`}>
        <div>
          <p className="font-semibold">Name:</p>
          <p className={`${darkMode ? "text-gray-200" : "text-gray-900"}`}>{user.name}</p>
        </div>
        <div>
          <p className="font-semibold">Email:</p>
          <p className={`${darkMode ? "text-gray-200" : "text-gray-900"}`}>{user.email}</p>
        </div>
        <div>
          <p className="font-semibold">Joined:</p>
          <p className={`${darkMode ? "text-gray-200" : "text-gray-900"}`}>
            {user.joinedDate && new Date(user.joinedDate).toLocaleDateString()}
          </p>
        </div>
      </div>

      {/* Logout Button */}
      <button
        onClick={onLogout}
        className={`mt-6 w-full py-3 rounded-xl transition-colors font-semibold ${
          darkMode
            ? "bg-red-600 hover:bg-red-700 text-white"
            : "bg-red-600 hover:bg-red-700 text-white"
        }`}
      >
        Logout
      </button>
    </div>
  );
}
